var e=[{id:`L2_1`,type:`narration`,speaker:null,text:{KOREA:`쾌걸이 쓰는 가면.`,JPN:`快傑が被る仮面。`,ENG:`The mask that Zorro wears.`,TWN:`英雄戴的面具。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`핍박으로 고통 받는 사람들을 구해 주는 가면.`,JPN:`虐待で苦しめられている人たちを救う仮面。`,ENG:`The mask that saves people suffering from oppression.`,TWN:`可以救人脫離痛苦的面具。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`narration`,speaker:null,text:{KOREA:`누나는 촌스럽다고 비웃었지만 나에게는 정말 멋져 보였어.`,JPN:`姉さんはダサいとか言いながら笑ってたけど、僕には本当にカッコよく見えた。`,ENG:`Sis always said it looked corny, but it looked so cool to me.`,TWN:`雖然姊姊笑它很土，我卻覺得無比帥氣。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`narration`,speaker:null,text:{KOREA:`저 가면만 있으면, 나도 두려워할 게 없을 것 같아서.`,JPN:`あの仮面さえあれば、怖いものがなくなりそうで。`,ENG:`I felt like I wouldn't be scared if I had a mask like that.`,TWN:`只要有那個面具，我就無所畏懼。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`저 녀석…… 왜 갑자기 움직이지 않는 거지?`,JPN:`あいつ……なんでいきなり止まったんだ？`,ENG:`Huh...? Why did he suddenly stop moving?`,TWN:`他……為何突然動也不動？`},stage:{bg:`COLOSSEUM`,slots:{L:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L9_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`루트? 어디 아파?`,JPN:`ルート？　どっか痛いの？`,ENG:`Root? Are you hurt?`,TWN:`路特？你哪裡不舒服嗎？`},stage:{bg:`COLOSSEUM`,slots:{L:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_MASK`,text:{KOREA:`크윽…….`,JPN:`くうっ……`,ENG:`Kgh...`,TWN:`呃……`},stage:{bg:`COLOSSEUM`,slots:{L:null,C:{char_id:`HAVEN_HAVEN_NULL_MASK`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_MASK`,text:{KOREA:`크아아악!!`,JPN:`グアァァッ！！`,ENG:`Kraaaagh!!!`,TWN:`呃啊啊啊！！`},stage:{bg:`COLOSSEUM`,slots:{L:null,C:{char_id:`HAVEN_HAVEN_NULL_MASK`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`어어!? 도로시, 루트의 CRF가 갑자기 엄청 커졌어!`,JPN:`ええっ！？　ドロシー、ルートのCRFがいきなりとてつもなく大きくなったよ！`,ENG:`Huh?! Dorothy! Root's CRF got really huge all of a sudden!`,TWN:`嗯！？桃樂絲，路特的CRF突然變很強！`},stage:{bg:`COLOSSEUM`,slots:{L:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L16_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`젠장, 뭐가 어떻게 된 거야!?`,JPN:`くそ、何がどうなってるんだ！？`,ENG:`What?! What's happening to him?!`,TWN:`該死，怎麼會這樣！？`},stage:{bg:`COLOSSEUM`,slots:{L:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L19_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>우와아아아아!</color>`,JPN:`<color=#ffd34c>うわああああ！</color>`,ENG:`<color=#ffd34c>YEAAAAAH!</color>`,TWN:`<color=#ffd34c>哇哇哇哇！</color>`},stage:{bg:`CLUB1`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>멀리서까지 전해지는 이 위압감! 역시 헤이븐 형님이야!!</color>`,JPN:`<color=#ffd34c>遠くからでも伝わるこの威圧感！　やっぱヘイブン兄貴だぜ！！</color>`,ENG:`<color=#ffd34c>You can feel his power from all the way over here! He’s the real deal!!</color>`,TWN:`<color=#ffd34c>遠遠的就可以感受到那股肅殺之氣！真不愧是天堂大哥！！</color>`},stage:{bg:`CLUB1`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`MC_HAVEN_NULL_NULL`,text:{KOREA:`<color=#ffd34c>그렇습니다, 여러분! 헤이븐 형님께서 드디어! 본때를 보여 주시려나 보군요!</color>`,JPN:`<color=#ffd34c>そうです、みなさん！　ヘイブン様がついに！　挑戦者に思い知らせてくれるようです！</color>`,ENG:`<color=#ffd34c>That's right, everyone! Finally! Mr. Haven has unleashed his full power!</color>`,TWN:`<color=#ffd34c>是的，各位！天堂大哥終於！要開始展露他的真本事！</color>`},stage:{bg:`CLUB1`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`PARK_NPC_HAVEN_NULL`,text:{KOREA:`헤론 님, 대결은 어떻게 되어 가고 있습니까?`,JPN:`ヘロン様、対決はどうなっていますか？`,ENG:`Madam Heron, how is the match going?`,TWN:`海倫夫人，請問目前比賽情況如何？`},stage:{bg:`CLUB1`,slots:{L:null,C:{char_id:`PARK_NPC_HAVEN_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`아, 왔군요. 휴스턴.`,JPN:`あ、来ましたね。ヒューストン。`,ENG:`Oh, Huston! You're here.`,TWN:`喔，你來啦，休士頓。`},stage:{bg:`CLUB1`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`호란은 어떻게 됐죠?`,JPN:`ホランはどうしましたか？`,ENG:`Did you take care of Horan?`,TWN:`小蘭怎麼樣？`},stage:{bg:`CLUB1`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};